import React from 'react';
import { Link } from 'react-router-dom';

const Login = () => {
  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>Welcome Back</h2>
        <p style={styles.subTitle}>Login to your <span style={{color: '#00d2ff'}}>Nexus.</span> account</p>
        
        <form style={styles.form}>
          <input type="email" placeholder="Email Address" style={styles.input} required />
          <input type="password" placeholder="Password" style={styles.input} required />
          <button type="submit" style={styles.btn}>Login</button>
        </form>

        <p style={styles.footerText}>
          Don't have an account? <Link to="/signup" style={styles.link}>Join Us</Link>
        </p>
      </div>
    </div>
  );
};

const styles = {
  container: { minHeight: '80vh', display: 'flex', justifyContent: 'center', alignItems: 'center' },
  card: { background: 'rgba(255,255,255,0.05)', backdropFilter: 'blur(15px)', padding: '50px', borderRadius: '30px', border: '1px solid rgba(255,255,255,0.1)', width: '100%', maxWidth: '400px', textAlign: 'center' },
  title: { fontSize: '32px', color: '#fff', marginBottom: '10px' },
  subTitle: { color: '#888', marginBottom: '30px' },
  form: { display: 'flex', flexDirection: 'column', gap: '15px' },
  input: { padding: '12px', borderRadius: '10px', border: '1px solid #333', background: '#111', color: '#fff', outline: 'none' },
  btn: { background: '#00d2ff', color: '#000', padding: '12px', border: 'none', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer', fontSize: '16px' },
  footerText: { marginTop: '20px', color: '#888' },
  link: { color: '#00d2ff', textDecoration: 'none', fontWeight: 'bold' }
};

export default Login;
